const cur = msg.payload.current;
const temp      = cur.temperature_2m;
const humidity  = cur.relative_humidity_2m;
const pressure  = cur.pressure_msl;       // hPa niveau mer
const windSpeed = cur.wind_speed_10m;
const windDir   = cur.wind_direction_10m;

// Stocker dans contexte global pour le keepalive
global.set('outdoor_temp',      temp);
global.set('outdoor_humidity',  humidity);
global.set('outdoor_pressure',  pressure);
global.set('outdoor_wind_speed', windSpeed);
global.set('outdoor_wind_dir',  windDir);

// Lire la production du jour calculée par les nodes MPPT/PVInverter
const todaysYield = global.get('total_yield_today') || 0;

node.status({fill: 'green', shape: 'dot', text: `${temp}°C — ${humidity}% — ${todaysYield.toFixed(2)} kWh`});

// Message 1 : capteur température/humidité/pression → com.victronenergy.temperature.mqtt_1 (instance 20)
const heatMsg = {
    topic:   'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     temp,
        TemperatureType: 4,
        Humidity:        humidity,
        Pressure:        pressure
    })
};

// Message 2 : capteur météo/irradiance → com.victronenergy.meteo (instance 40)
const meteoMsg = {
    topic:   'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:          0,
        TodaysYield:         todaysYield,
        ExternalTemperature: temp,
        WindSpeed:           windSpeed,
        WindDirection:       windDir
    })
};

return [[heatMsg, meteoMsg]];

const temp      = global.get('outdoor_temp');
const humidity  = global.get('outdoor_humidity');
const pressure  = global.get('outdoor_pressure');
const windSpeed = global.get('outdoor_wind_speed');
const windDir   = global.get('outdoor_wind_dir');

// Attendre la première récupération Open-Meteo
if (temp === undefined || temp === null) {
    return null;
}

// Production du jour (mise à jour par MPPT/PVInverter)
const todaysYield = global.get('total_yield_today') || 0;

const heatMsg = {
    topic:   'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     temp,
        TemperatureType: 4,
        Humidity:        humidity,
        Pressure:        pressure
    })
};

const meteoMsg = {
    topic:   'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:          0,
        TodaysYield:         todaysYield,
        ExternalTemperature: temp,
        WindSpeed:           windSpeed,
        WindDirection:       windDir
    })
};

return [[heatMsg, meteoMsg]];

const val = msg.payload && msg.payload.value !== undefined ? msg.payload.value : msg.payload;
if (val === null || val === undefined || isNaN(val)) return null;

// Stocker par topic (supporte plusieurs MPPT)
let mpptYields = global.get('mppt_yields') || {};
mpptYields[msg.topic] = parseFloat(val) || 0;
global.set('mppt_yields', mpptYields);

// Sommer tous les MPPT
const mpptTotal = Object.values(mpptYields).reduce((a, b) => a + b, 0);
global.set('mppt_yield_today', mpptTotal);

// Mettre à jour le total combiné
const pvinvYield = global.get('pvinv_yield_today') || 0;
const total = parseFloat((mpptTotal + pvinvYield).toFixed(3));
global.set('total_yield_today', total);

node.status({fill: 'green', shape: 'dot', text: `MPPT: ${mpptTotal.toFixed(2)} kWh | Total: ${total.toFixed(2)} kWh`});
return msg;

const val = msg.payload && msg.payload.value !== undefined ? msg.payload.value : msg.payload;
if (val === null || val === undefined || isNaN(val)) return null;

const current = parseFloat(val);

// Initialiser la baseline au premier message (ou après reset minuit)
let baseline = global.get('pvinv_baseline');
if (baseline === null || baseline === undefined) {
    global.set('pvinv_baseline', current);
    baseline = current;
}

// Delta = énergie produite depuis le début du jour
const dailyYield = Math.max(0, parseFloat((current - baseline).toFixed(3)));
global.set('pvinv_yield_today', dailyYield);

// Mettre à jour le total combiné
const mpptYield = global.get('mppt_yield_today') || 0;
const total = parseFloat((mpptYield + dailyYield).toFixed(3));
global.set('total_yield_today', total);

node.status({fill: 'blue', shape: 'dot', text: `PVInv: ${dailyYield.toFixed(2)} kWh | Total: ${total.toFixed(2)} kWh`});
return msg;

// Réinitialiser la baseline du PVInverter pour le nouveau jour
// La prochaine valeur reçue depuis N/.../pvinverter/32/Ac/Energy/Forward
// deviendra la nouvelle baseline (delta = 0 à minuit).
global.set('pvinv_baseline', null);
global.set('pvinv_yield_today', 0);
// Les yields MPPT sont remis à zéro par Venus OS lui-même à minuit
global.set('mppt_yields', {});
global.set('mppt_yield_today', 0);
global.set('total_yield_today', 0);
node.status({fill: 'blue', shape: 'dot', text: 'Reset minuit OK'});
return msg;
